// Extract enrichment data from OpenSearch response
const osData = $input.first().json;
const grafanaAlert = $('CrowdSec Webhook').first().json.body;
const alert = (grafanaAlert.alerts || [{}])[0];

// Parse aggregation results
const totalBans = osData.hits?.total?.value || 0;
const bannedIps = (osData.aggregations?.banned_ips?.buckets || [])
  .map(b => {
    // Extract IP from ban message like "ban on Ip 1.2.3.4"
    const match = b.key.match(/ban on Ip\s+([\d.]+)/);
    return match ? `\`${match[1]}\` (${b.doc_count}x)` : `${b.key.slice(0, 40)} (${b.doc_count}x)`;
  })
  .slice(0, 8)
  .join('\n') || 'None in last hour';

const programs = (osData.aggregations?.by_program?.buckets || [])
  .map(b => `${b.key}: ${b.doc_count}`)
  .join(', ') || 'N/A';

const sources = (osData.aggregations?.by_source?.buckets || [])
  .map(b => `${b.key}: ${b.doc_count}`)
  .join(', ') || 'N/A';

return [{
  json: {
    alertName: alert.labels?.alertname || 'CrowdSec Alert',
    severity: alert.labels?.severity || 'warning',
    summary: alert.annotations?.summary || 'CrowdSec ban decision surge detected',
    description: alert.annotations?.description || '',
    startsAt: alert.startsAt || new Date().toISOString(),
    dashboardURL: alert.dashboardURL || '',
    panelURL: alert.panelURL || '',
    totalBans,
    bannedIps,
    programs,
    sources,
    labels: alert.labels || {}
  }
}];

